# This function is used to process financial transactions.
def process_transaction(account, amount):
    # Update the balance of the account.
    account["balance"] += amount

    # Return the updated account object.
    return account


# This function is used to update the balance of all accounts in a list.
def update_balances(accounts):
    for index, account in enumerate(accounts):
        # Process each transaction on this account.
        for transaction in account["transactions"]:
            # Update the balance using the process_transaction() function.
            account = process_transaction(account, transaction)

        accounts[index] = account

    return accounts